import React, { useState, useEffect } from "react";

const API_URL = "https://laptimeapp-backend.onrender.com/api/laptimes";

function App() {
    const [lapTimes, setLapTimes] = useState([]);
    const [error, setError] = useState(null);

    // Fetch lap times on component load
    useEffect(() => {
        fetchLapTimes();
    }, []);

    const fetchLapTimes = async () => {
        try {
            const response = await fetch(API_URL);
            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }
            const data = await response.json();
            setLapTimes(data);
        } catch (err) {
            console.error("Error fetching lap times:", err);
            setError(err.message);
        }
    };

    return (
        <div>

            <div class="container">
                <div id="row">
                    <div id="col">
                        <h1>Lap Times</h1>
                    </div>
                </div>
                
                <div class="row">
                    <div class="col">
                        <button onClick={fetchLapTimes}>Fetch Lap Times</button>
                        {error && <p style={{ color: "red" }}>Error: {error}</p>}
                    </div>
                </div>

                <div id="row">
                    <div class="col" style={{ padding: "0px"}}>
                        {/* Render Table */}
                        {lapTimes.length > 0 ? (
                            <table border="3" style={{ marginTop: "20px", width: "100%", textAlign: "center", borderCollapse: "collapse", padding: "0px"}} class="table table-striped">
                                <thead>
                                    <tr>
                                        <th>Driver</th>
                                        <th>Track</th>
                                        <th>Lap Time (s)</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {lapTimes.map((lap, index) => (
                                        <tr key={index}>
                                            <td>{lap.driver}</td>
                                            <td>{lap.track}</td>
                                            <td>{lap.lapTime}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        ) : (
                            <p>No lap times to display</p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

export default App;
